{"command": "cat ~/.openclaw/cron/jobs.json | python3 -c "
import json, sys
data = json.load(sys.stdin)
# Show a delivery-only cron with deleteAfterRun as example
for j in data['jobs']:
    d = j.get('delivery', {})
    if d.get('deleteAfterRun') == True:
        print(json.dumps(j, indent=2, ensure_ascii=False))
        break
else:
    print('No deleteAfterRun job found')
""}

{"command": "cat ~/.openclaw/cron/jobs.json | python3 -c "
import json, sys
data = json.load(sys.stdin)
# Count and show a few sample jobs with delivery settings
for j in data['jobs']:
    d = j.get('delivery', {})
    if d.get('mode') == 'announce':
        print(json.dumps({k: v for k, v in j.items() if k != 'payload'}, indent=2, ensure_ascii=False))
        print('---')
" 2>/dev/null | head -60"}

{"command": "cat ~/.openclaw/cron/jobs.json | python3 -c "
import json, sys
data = json.load(sys.stdin)
for j in data['jobs']:
    d = j.get('delivery', {})
    if 'message' in d:
        print(json.dumps({k: v for k, v in j.items() if k != 'payload'}, indent=2, ensure_ascii=False))
        print('MSG:', d['message'][:100])
        print('---')
""}

